form.style:
width:100%; max-width:450px; background: rgba(14, 21, 16, 0.97); border-width: 1px !important;
                             border-style: solid !important; border-color: #ffffff1f !important;
                             padding:30px; border-radius:16px; box-shadow:0 10px 30px rgba(0,0,0,0.08);

xpath.script:
document.addEventListener("DOMContentLoaded", function () {
const profileInput = document.getElementById('profile_pic_input');
if (profileInput) {
profileInput.addEventListener('change', function(event) {
const file = event.target.files[0];
if (file) {
const preview = document.getElementById('profile_pic_preview');
preview.src = URL.createObjectURL(file);
preview.style.display = 'block';
}
});
}
const savedForm = localStorage.getItem('signup_form_data');
if (savedForm) {
try {
const data = JSON.parse(savedForm);
Object.keys(data).forEach(name => {
const el = document.querySelector(`[name="${name}"]`);
if (el && el.type !== "file") {
el.value = data[name];
}
});
} catch (e) {
console.error("Form restore error:", e);
}
}

const selfieData = localStorage.getItem('selfie');
if (selfieData) {
const preview = document.getElementById('selfie_preview');
const input = document.getElementById('selfie_input');
const btn = document.getElementById('selfie_btn');
if (input) input.value = selfieData;
if (preview) {
preview.src = selfieData;
preview.style.display = "block";
}

if (btn) btn.innerText = "Submit Verification";
}

const btn = document.getElementById('selfie_btn');
if (btn) {
btn.addEventListener('click', function () {
const form = document.querySelector('.oe_signup_form');
if (!form) return;
const data = {};
form.querySelectorAll('input, textarea, select').forEach(el => {
if (el.name && el.type !== "file" && el.type !== "password") {
data[el.name] = el.value;
}
});
localStorage.setItem('signup_form_data', JSON.stringify(data));
});
}
const form = document.querySelector('.oe_signup_form');
if (form) {
form.addEventListener('submit', function () {
localStorage.removeItem('selfie');
localStorage.removeItem('signup_form_data');
});
}
});
function openCamera() {
window.location.href = "/selfie-capture";
}

t.script:
document.addEventListener("DOMContentLoaded", async function () {
const video = document.getElementById('video');
const canvas = document.getElementById('canvas');
const btn = document.getElementById('capture_btn');
if (!video || !canvas || !btn) {
console.error("Camera DOM not found");
return;
}
let streamRef = null;
try {
const stream = await navigator.mediaDevices.getUserMedia({
video: { facingMode: "user" },
audio: false
});
streamRef = stream;
video.srcObject = stream;
await video.play();
} catch (err) {
console.error("Camera error:", err);
alert("Camera not working: " + err.message);
return;
}
btn.addEventListener("click", captureSelfie);
function captureSelfie() {
const ctx = canvas.getContext('2d');
canvas.width = video.videoWidth;
canvas.height = video.videoHeight;
ctx.drawImage(video, 0, 0);
const data = canvas.toDataURL('image/png');
localStorage.setItem('selfie', data);
if (streamRef) {
streamRef.getTracks().forEach(t => t.stop());
}
window.location.href = "/web/signup";
}
});
